import javax.swing.ImageIcon;
import javax.swing.JButton;
import javax.swing.JFrame;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JTabbedPane;
import java.awt.BorderLayout;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Font;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;

public class MainClass {

    private static final String TAB_STYLE = "<html><body style='width: 100px; height: 30px; "
        + "background-color: #D5E5F9; border: 2px solid #77AADD; border-radius: 10px;'>";

    public static void main(String[] args) {
        JFrame frame = new JFrame("Tabbed Pane Example");
        JTabbedPane tabbedPane = new JTabbedPane();

        VueClientTab vueClientTab = new VueClientTab();
        tabbedPane.addTab("Vue Client", vueClientTab.getPanel());

        OtherTab otherTab = new OtherTab();
        tabbedPane.addTab("Other", otherTab.getPanel());

        Dimension addTabBtnSize = new Dimension(25, 25);
        JButton addTabBtn = new JButton(new ImageIcon("path-to-image.png"));
        addTabBtn.setPreferredSize(addTabBtnSize);
        addTabBtn.addActionListener(new ActionListener() {
            public void actionPerformed(ActionEvent e) {
                JPanel newPanel = new JPanel();
                newPanel.add(new JLabel("This is a new tab."));
                tabbedPane.addTab(TAB_STYLE + "+ New Tab</body></html>", newPanel);
                int index = tabbedPane.indexOfTab(TAB_STYLE + "+ New Tab</body></html>");
                tabbedPane.setTabComponentAt(index, new CloseableTab(TAB_STYLE + "New Tab</body></html>"));
                tabbedPane.setSelectedIndex(index);
            }
        });

        CloseableTab firstTab = new CloseableTab(TAB_STYLE + "<b>Vue Client</b></body></html>");
        tabbedPane.setTabComponentAt(0, firstTab);
        CloseableTab secondTab = new CloseableTab(TAB_STYLE + "<b>Other</b></body></html>");
        tabbedPane.setTabComponentAt(1, secondTab);

        JPanel addButtonPanel = new JPanel();
        addButtonPanel.add(addTabBtn);

        frame.add(addButtonPanel, BorderLayout.NORTH);
        frame.add(tabbedPane);
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.pack();
        frame.setVisible(true);
    }

    private static class CloseButton extends JButton {
        private CloseButton() {
            setPreferredSize(new Dimension(15, 15));
            setToolTipText("Close Tab");
        }
    }

    private static class CloseableTab extends JPanel {

        public CloseableTab(String title) {
            setOpaque(false);
            JLabel label = new JLabel(title);
            label.setFont(new Font("Arial", Font.BOLD, 12));
            CloseButton closeButton = new CloseButton();
            closeButton.addActionListener(new ActionListener() {
                @Override
                public void actionPerformed(ActionEvent e) {
                    JTabbedPane tabbedPane = (JTabbedPane) getParent().getParent();
                    int index = tabbedPane.indexOfTabComponent(CloseableTab.this);
                    if (index != -1) {
                        tabbedPane.removeTabAt(index);
                    }
                }
            });
            add(label);
            add(closeButton);
        }
    }
}
```

In this example, the `TAB_STYLE` variable is set to a string that contains the HTML and CSS styling for the tab. The string sets the width and height of the tab, as well as the background color, border style, and border radius.

The `addTabBtn` object is created using an image icon, but you can change this to any other image file. The button's size is set using a `Dimension` object.

The `CloseableTab` class is used to create the closeable tabs that have an "X" button to close the tab. The class sets the tab's background color to be transparent, and adds a `JLabel` for the tab title and a `JButton` for the close button.

You can customize the styling of the tabs and buttons by modifying the CSS styles or the image files used.

